:root {
    --primary: #4A90D9;
    --primary-dark: #357ABD;
    --secondary: #2C3E50;
    --accent: #E74C3C;
    --bg-dark: #1a1a2e;
    --bg-light: #16213e;
    --bg-card: #0f3460;
    --text-primary: #ffffff;
    --text-secondary: #a0a0a0;
    --success: #27ae60;
    --warning: #f39c12;
    --error: #e74c3c;
    --border: #2a2a4a;
}

:root.light-mode {
    --bg-dark: #f5f5f5;
    --bg-light: #ffffff;
    --bg-card: #e8e8e8;
    --text-primary: #1a1a2e;
    --text-secondary: #555555;
    --border: #d0d0d0;
}

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html, body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, sans-serif;
    background: var(--bg-dark);
    color: var(--text-primary);
    min-height: 100vh;
    overflow-x: hidden;
}

body {
    display: flex;
}

.sidebar {
    width: 280px;
    min-width: 280px;
    max-width: 280px;
    background: var(--bg-light);
    border-right: 1px solid var(--border);
    position: fixed;
    height: 100vh;
    top: 0;
    left: 0;
    z-index: 1000;
    display: flex;
    flex-direction: column;
}

